315→    private fun readIdentity(): Identity {
316→        var name: String? = null
317→        var email: String? = null
318→        var description: String? = null
319→        var settings: SettingsMap? = null
320→
321→        readElement { eventType ->
322→            if (eventType == XmlPullParser.START_TAG) {
323→                when (pullParser.name) {
324→                    SettingsExporter.NAME_ELEMENT -> {
325→                        name = readText()
326→                    }
327→                    SettingsExporter.EMAIL_ELEMENT -> {
328→                        email = readText()
329→                    }
330→                    SettingsExporter.DESCRIPTION_ELEMENT -> {
331→                        description = readText()
332→                    }
333→                    SettingsExporter.SETTINGS_ELEMENT -> {
334→                        settings = readSettingsContainer()
335→                    }
336→                    else -> {
337→                        skipElement()
338→                    }
339→                }
340→            }
341→        }
342→
343→        return Identity(name, email, description, settings)
344→    }
345→
346→    private fun readFolders(): List<Folder> {
347→        val folders = mutableListOf<Folder>()
348→
349→        readElement { eventType ->
350→            if (eventType == XmlPullParser.START_TAG) {
351→                when (pullParser.name) {
352→                    SettingsExporter.FOLDER_ELEMENT -> {
353→                        val folder = readFolder()
354→                        if (folder != null) {
355→                            folders.add(folder)
356→                        }
357→                    }
358→                    else -> {
359→                        skipElement()
360→                    }
361→                }
362→            }
363→        }
364→
365→        return folders
366→    }
367→
368→    private fun readFolder(): Folder? {
369→        val name = pullParser.getAttributeValue(null, SettingsExporter.NAME_ATTRIBUTE) ?: return null
370→        val settings = readSettingsContainer()
371→
372→        return Folder(name, settings)
373→    }
374→
375→    private fun readText(): String {
376→        return if (pullParser.next() == XmlPullParser.TEXT) {
377→            pullParser.text
378→        } else {
379→            ""
380→        }
381→    }
382→
383→    private fun readAttribute(name: String): String {
384→        return pullParser.getAttributeValue(null, name) ?: parserError("Missing '$name' attribute")
385→    }
386→
387→    private fun readElement(block: (Int) -> Unit) {
388→        require(pullParser.eventType == XmlPullParser.START_TAG)
389→
390→        val tagName = pullParser.name
391→        val depth = pullParser.depth
392→        while (true) {
393→            when (val eventType = pullParser.next()) {
394→                XmlPullParser.END_DOCUMENT -> {
395→                    parserError("End of document reached while reading element '$tagName'")
396→                }
397→                XmlPullParser.END_TAG -> {
398→                    if (pullParser.name == tagName && pullParser.depth == depth) return
399→                }
400→                else -> {
401→                    block(eventType)
402→                }
403→            }
404→        }
405→    }
406→
407→    private fun skipElement() {
408→        Timber.d("Skipping element '%s'", pullParser.name)
409→        readElement { /* Do nothing */ }
410→    }
411→
412→    private fun parserError(message: String): Nothing {
413→        throw SettingsParserException(message)
414→    }
415→}
