413→        }
414→
415→        @Override
416→        public Integer fromString(String value) throws InvalidSettingValueException {
417→            try {
418→                Integer fontSize = Integer.parseInt(value);
419→                if (mapping.containsKey(fontSize)) {
420→                    return fontSize;
421→                }
422→            } catch (NumberFormatException e) { /* do nothing */ }
423→
424→            throw new InvalidSettingValueException();
