 1→package app.k9mail.feature.settings.import.ui
 2→
 3→import android.content.Context
 4→import android.content.pm.PackageManager
 5→import androidx.annotation.WorkerThread
 6→
 7→internal class ImportAppFetcher(
 8→    private val context: Context,
 9→) {
10→    private val packageManager by lazy { context.packageManager }
11→
12→    /**
13→     * Returns `true` if at least one app is installed from which we can import settings.
14→     */
15→    @WorkerThread
16→    fun isAtLeastOneAppInstalled(): Boolean {
17→        return supportedApps.any { packageName -> packageManager.isAppInstalled(packageName) }
18→    }
19→
20→    @Suppress("SwallowedException")
21→    private fun PackageManager.isAppInstalled(packageName: String): Boolean {
22→        return try {
23→            getApplicationInfo(packageName, 0)
24→            true
25→        } catch (e: PackageManager.NameNotFoundException) {
26→            false
27→        }
28→    }
29→
30→    /**
31→     * Get list of apps from which we can import settings.
32→     */
33→    @WorkerThread
34→    fun getAppInfoList(): List<AppInfo> {
35→        return supportedApps
36→            .mapNotNull { packageName -> packageManager.loadAppInfo(packageName) }
37→            .toList()
38→    }
39→
40→    @Suppress("SwallowedException")
41→    private fun PackageManager.loadAppInfo(packageName: String): AppInfo? {
42→        return try {
43→            val applicationInfo = getApplicationInfo(packageName, 0)
44→            val appName = packageManager.getApplicationLabel(applicationInfo).toString()
45→
46→            AppInfo(packageName, appName)
47→        } catch (e: PackageManager.NameNotFoundException) {
48→            null
49→        }
50→    }
51→
52→    /**
53→     * Get the list of application IDs of supported apps excluding our own app.
54→     */
55→    private val supportedApps: Sequence<String>
56→        get() {
57→            val myPackageName = context.packageName
58→            return SUPPORTED_APPS
59→                .asSequence()
60→                .filterNot { packageName -> packageName == myPackageName }
61→        }
62→
63→    companion object {
64→        private val SUPPORTED_APPS = listOf(
65→            // K-9 Mail
66→            "com.fsck.k9",
67→            // Thunderbird for Android (release)
68→            "net.thunderbird.android",
69→            // Thunderbird for Android (beta)
70→            "net.thunderbird.android.beta",
71→            // Thunderbird for Android (daily)
72→            "net.thunderbird.android.daily",
73→        )
74→    }
75→}
76→
77→internal data class AppInfo(val packageName: String, private val appName: String) {
78→    // ArrayAdapter is using `toString()` when rendering list items. See PickAppDialogFragment.
79→    override fun toString() = appName
80→}
