364→    private fun startImportSettings() {
365→        val contentUri = this.contentUri ?: error("contentUri is missing")
366→        viewModelScope.launch {
367→            try {
368→                val containsGeneralSettings = this@SettingsImportViewModel.containsGeneralSettings
369→                val importGeneralSettings = containsGeneralSettings && includeGeneralSettings
370→                val importAccounts = selectedAccounts.toList()
371→
372→                val (elapsed, importResults) = measureRealtimeMillisWithResult {
373→                    withContext(backgroundDispatcher) {
374→                        importSettings(contentUri, importGeneralSettings, importAccounts)
375→                    }
376→                }
377→
378→                if (elapsed < MIN_PROGRESS_DURATION) {
379→                    delay(MIN_PROGRESS_DURATION - elapsed)
380→                }
381→
382→                updateUiModel {
383→                    if (containsGeneralSettings) {
384→                        setGeneralSettingsImportStatus(importResults, importGeneralSettings)
385→                    }
386→                    setAccountsImportStatus(importResults)
387→
388→                    updateCloseButtonAndImportStatusText()
389→                }
390→            } catch (e: Exception) {
391→                Timber.e(e, "Error importing settings")
392→
393→                updateUiModel {
394→                    showImportErrorText()
395→                }
396→            }
397→        }
398→    }
