 12→import com.fsck.k9.preferences.K9StoragePersister.StoragePersistOperationCallback;
 13→import com.fsck.k9.preferences.K9StoragePersister.StoragePersistOperations;
 14→import timber.log.Timber;
 15→
 16→
 17→public class K9StorageEditor implements StorageEditor {
 18→    private StorageUpdater storageUpdater;
 19→    private K9StoragePersister storagePersister;
 20→
 21→    private Map<String, String> changes = new HashMap<>();
 22→    private List<String> removals = new ArrayList<>();
 23→
 24→
 25→    public K9StorageEditor(StorageUpdater storageUpdater, K9StoragePersister storagePersister) {
 26→        this.storageUpdater = storageUpdater;
 27→        this.storagePersister = storagePersister;
 28→    }
 29→
 30→    @Override
 31→    public boolean commit() {
 32→        try {
 33→            storageUpdater.updateStorage(this::commitChanges);
 34→            return true;
 35→        } catch (Exception e) {
 36→            Timber.e(e, "Failed to save preferences");
 37→            return false;
 38→        }
 39→    }
 40→
 41→    private Storage commitChanges(Storage storage) {
 42→        long startTime = SystemClock.elapsedRealtime();
 43→        Timber.i("Committing preference changes");
 44→
 45→        Map<String, String> newValues = new HashMap<>();
 46→        Map<String, String> oldValues = storage.getAll();
 47→        StoragePersistOperationCallback committer = new StoragePersistOperationCallback() {
 48→            @Override
 49→            public void beforePersistTransaction(Map<String, String> workingStorage) {
 50→                workingStorage.putAll(oldValues);
 51→            }
 52→
 53→            @Override
 54→            public void persist(StoragePersistOperations ops) {
 55→                for (String removeKey : removals) {
 56→                    ops.remove(removeKey);
 57→                }
 58→                for (Entry<String, String> entry : changes.entrySet()) {
 59→                    String key = entry.getKey();
 60→                    String newValue = entry.getValue();
 61→                    String oldValue = oldValues.get(key);
 62→                    if (removals.contains(key) || !newValue.equals(oldValue)) {
 63→                        ops.put(key, newValue);
 64→                    }
 65→                }
 66→            }
 67→
 68→            @Override
 69→            public void onPersistTransactionSuccess(Map<String, String> workingStorage) {
 70→                newValues.putAll(workingStorage);
 71→            }
 72→        };
 73→        storagePersister.doInTransaction(committer);
 74→        long endTime = SystemClock.elapsedRealtime();
 75→        Timber.i("Preferences commit took %d ms", endTime - startTime);
 76→
 77→        return new Storage(newValues);
 78→    }
 79→
 80→    @Override
 81→    public StorageEditor putBoolean(String key,
 82→            boolean value) {
 83→        changes.put(key, "" + value);
 84→        return this;
 85→    }
 86→
 87→    @Override
 88→    public StorageEditor putInt(String key, int value) {
 89→        changes.put(key, "" + value);
 90→        return this;
 91→    }
 92→
 93→    @Override
 94→    public StorageEditor putLong(String key, long value) {
 95→        changes.put(key, "" + value);
 96→        return this;
 97→    }
 98→
 99→    @Override
100→    public StorageEditor putString(String key, String value) {
101→        if (value == null) {
102→            remove(key);
103→        } else {
104→            changes.put(key, value);
105→        }
106→        return this;
107→    }
