 8→class BackendManager(private val backendFactories: Map<String, BackendFactory>) {
 9→    private val backendCache = mutableMapOf<String, BackendContainer>()
10→    private val listeners = CopyOnWriteArraySet<BackendChangedListener>()
11→
12→    fun getBackend(account: Account): Backend {
13→        val newBackend = synchronized(backendCache) {
14→            val container = backendCache[account.uuid]
15→            if (container != null && isBackendStillValid(container, account)) {
16→                return container.backend
17→            }
18→
19→            createBackend(account).also { backend ->
20→                backendCache[account.uuid] = BackendContainer(
21→                    backend,
22→                    account.incomingServerSettings,
23→                    account.outgoingServerSettings,
24→                )
25→            }
26→        }
27→
28→        notifyListeners(account)
29→
30→        return newBackend
31→    }
32→
33→    private fun isBackendStillValid(container: BackendContainer, account: Account): Boolean {
34→        return container.incomingServerSettings == account.incomingServerSettings &&
35→            container.outgoingServerSettings == account.outgoingServerSettings
36→    }
37→
38→    fun removeBackend(account: Account) {
39→        synchronized(backendCache) {
40→            backendCache.remove(account.uuid)
41→        }
42→
43→        notifyListeners(account)
44→    }
45→
46→    private fun createBackend(account: Account): Backend {
47→        val serverType = account.incomingServerSettings.type
48→        val backendFactory = backendFactories[serverType] ?: error("Unsupported account type")
49→        return backendFactory.createBackend(account)
50→    }
51→
52→    fun addListener(listener: BackendChangedListener) {
53→        listeners.add(listener)
54→    }
55→
56→    fun removeListener(listener: BackendChangedListener) {
57→        listeners.remove(listener)
58→    }
59→
60→    private fun notifyListeners(account: Account) {
61→        for (listener in listeners) {
62→            listener.onBackendChanged(account)
63→        }
64→    }
65→}
